+        tier: MemoryPressureTier::Red,
+        cold_batch_size: 100,
+        cold_reflow_paused: true,
+        overscan_cap: 32,
+        backlog_cap: 1000,
+        compact_before_resize: true,
+        compaction_batch_size: 64,
+        max_scratch_bytes: 1024,
